// Parse Birdeye OHLCV + prepare Scanner payload
const loopItem    = $('Loop Tokens').item.json;
const rawResponse = $input.item.json;

// Parse candles from Birdeye format
const items = rawResponse?.data?.items || [];
if (items.length < 50) {
  return []; // nedostatek dat ŌåÆ p┼Öesko─Źit token
}

const candles = items.map(c => ({
  timestamp: new Date(c.unixTime * 1000).toISOString(),
  open:   parseFloat(c.open),
  high:   parseFloat(c.high),
  low:    parseFloat(c.low),
  close:  parseFloat(c.close),
  volume: parseFloat(c.volume)
}));

// Vypo─Ź├Łtej SMA20 volume (pr┼»m─ør posledn├Łch 20 sv├Ł─Źek)
const recentVolumes = candles.slice(-21, -1).map(c => c.volume);
const volSma20 = recentVolumes.reduce((a, b) => a + b, 0) / recentVolumes.length;

return [{
  json: {
    symbol:        loopItem.symbol,
    display_name:  loopItem.display_name,
    token_address: loopItem.token_address,
    decimals:      loopItem.decimals || 6,
    liquidity_usd: loopItem.liquidity_usd || 0,
    chain:         'solana',
    candles,
    latest_volume: candles[candles.length - 1]?.volume || 0,
    vol_sma20
  }
}];

// Check if scanner detected a breakout signal for this DEX token
const scannerOutput = $input.item.json;
const loopItem      = $('Loop Tokens').item.json;

let signal = null;
try {
  const parsed = typeof scannerOutput.output === 'string'
    ? JSON.parse(scannerOutput.output)
    : scannerOutput.output;
  if (parsed?.signal && parsed.signal !== 'none') {
    signal = {
      symbol:        loopItem.symbol,
      display_name:  loopItem.display_name,
      token_address: loopItem.token_address,
      decimals:      loopItem.decimals || 6,
      liquidity_usd: loopItem.liquidity_usd || 0,
      chain:         'solana',
      direction:     parsed.signal,
      signal_data:   parsed
    };
  }
} catch {}

if (!signal) return [];
return [{ json: signal }];

// P┼Öiprav vstup pro Analyst agenta (DEX verze)
const signal     = $('Loop Analyst').item.json;
const portfolio  = $('Get DEX Portfolio').first().json;

// MindsDB predikce (pokud dostupn├Ī)
let mindsdb_prediction = null;
try {
  const mdbRaw = $input.first().json;
  if (mdbRaw?.data?.length > 0) {
    const row = mdbRaw.data[0];
    if (row?.direction) {
      mindsdb_prediction = {
        direction:          row.direction,
        confidence:         row.confidence != null ? parseFloat(row.confidence) : null,
        predicted_move_pct: row.predicted_move_pct != null ? parseFloat(row.predicted_move_pct) : null
      };
    }
  }
} catch {}

return [{
  json: {
    signal_id:         signal.id,
    symbol:            signal.symbol,
    display_name:      signal.display_name,
    token_address:     signal.token_address,
    decimals:          signal.decimals,
    liquidity_usd:     signal.liquidity_usd,
    chain:             'solana',
    direction:         signal.direction,
    signal_data:       signal.signal_data,
    portfolio,
    mindsdb_prediction
  }
}];

// Parse Analyst output ŌåÆ trade card (DEX)
const analystOutput  = $input.item.json;
const preparedInput  = $('Prepare Analyst Input').item.json;

let tradeCard = null;
try {
  const parsed = typeof analystOutput.output === 'string'
    ? JSON.parse(analystOutput.output)
    : analystOutput.output;
  tradeCard = {
    ...parsed,
    signal_id:         preparedInput.signal_id,
    symbol:            preparedInput.symbol,
    display_name:      preparedInput.display_name,
    token_address:     preparedInput.token_address,
    decimals:          preparedInput.decimals,
    liquidity_usd:     preparedInput.liquidity_usd,
    chain:             'solana',
    mindsdb_prediction: preparedInput.mindsdb_prediction
  };
} catch { return []; }

if (!tradeCard) return [];
return [{ json: tradeCard }];

// Parse Risk Controller output
const rcOutput    = $input.item.json;
const tradeCard   = $('Parse Analyst').item.json;

let rcResult = null;
try {
  rcResult = typeof rcOutput.output === 'string'
    ? JSON.parse(rcOutput.output)
    : rcOutput.output;
} catch { return []; }

if (!rcResult) return [];
return [{ json: { ...tradeCard, rc_decision: rcResult.decision, rc_reason: rcResult.reason, rc_data: rcResult } }];

// Compose DEX trade card Telegram message
const tc = $input.item.json;

const dir     = tc.direction?.toUpperCase() || '?';
const dirEmoji = dir === 'LONG'  ? '­¤ōł' : dir === 'SHORT' ? '­¤ōē' : 'ŌÜĀ’ĖÅ';
const chain   = 'ŌÜĪ Solana DEX';

const entry   = tc.entry_price      != null ? tc.entry_price.toFixed(6)      : '?';
const sl      = tc.stop_loss        != null ? tc.stop_loss.toFixed(6)        : '?';
const tp      = tc.take_profit      != null ? tc.take_profit.toFixed(6)      : '?';
const pos     = tc.position_size_usdt != null ? `$${tc.position_size_usdt.toFixed(2)}` : '?';
const rr      = tc.risk_reward_ratio  != null ? tc.risk_reward_ratio.toFixed(2) : '?';
const conf    = tc.confidence_score   != null ? `${(tc.confidence_score * 100).toFixed(0)}%` : '?';
const liq     = tc.liquidity_usd     != null ? `$${(tc.liquidity_usd / 1000).toFixed(0)}k` : '?';
const slipBps = tc.suggested_slippage || 50;

const lines = [
  `${dirEmoji} *DEX Signal: ${tc.display_name || tc.symbol}*`,
  `${chain}`,
  ``,
  `Sm─ør: *${dir}*`,
  `Vstup: \`${entry}\``,
  `SL: \`${sl}\`  |  TP: \`${tp}\``,
  `Pozice: *${pos}*  |  R:R ${rr}`,
  `Likvidita poolu: ${liq}  |  Slippage: ${slipBps}bps`,
  `Konfiden─Źn├Ł sk├│re: ${conf}`,
];

if (tc.mindsdb_prediction?.direction) {
  const movePct = tc.mindsdb_prediction.predicted_move_pct != null
    ? `, ${tc.mindsdb_prediction.predicted_move_pct > 0 ? '+' : ''}${tc.mindsdb_prediction.predicted_move_pct}% predikce`
    : '';
  lines.push(`­¤ż¢ MindsDB: ${tc.mindsdb_prediction.direction}${movePct}`);
}

lines.push(``, `Token: \`${tc.token_address}\``);
lines.push(`Signal ID: ${tc.signal_id}`);
lines.push(``, `/approve_${tc.signal_id} | /reject_${tc.signal_id}`);

return [{ json: { text: lines.join('\n'), signal_id: tc.signal_id, parse_mode: 'Markdown' } }];
